HEAD = '\ufeff<!DOCTYPE html>\n<html lang="zh-CN" class="light">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <meta name="theme-color" content="#F5F2EF">\n    <title>布依族词典</title>\n    <link rel="preconnect" href="https://fonts.googleapis.com">\n    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>\n    <link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=Noto+Serif+SC:wght@500;600;700;900&display=swap" rel="stylesheet">\n    <link rel="stylesheet" href="../liquid-glass.css">\n    <style>\n        /* ===== Cinematic Hero ===== */\n        .hero {\n            position: relative;\n            min-height: calc(100svh - 48px);\n            display: flex;\n            align-items: flex-end;\n            padding: 0 24px 80px;\n            overflow: hidden;\n        }\n        .hero-bg {\n            position: absolute;\n            inset: 0;\n            z-index: 0;\n        }\n        .hero-bg img {\n            width: 100%;\n            height: 100%;\n            object-fit: cover;\n            display: block;\n            animation: heroImgReveal 1.4s cubic-bezier(0.32,0.72,0,1) both;\n        }\n        .hero-scrim {\n            position: absolute;\n            inset: 0;\n            z-index: 1;\n            background:\n                linear-gradient(105deg, \n                    rgba(27,58,92,0.94) 0%, \n                    rgba(27,58,92,0.80) 28%, \n                    rgba(27,58,92,0.34) 58%, \n                    rgba(27,58,92,0.06) 100%),\n                linear-gradient(to top, \n                    rgba(27,58,92,0.90) 0%, \n                    transparent 55%);\n        }\n        .hero-content {\n            position: relative;\n            z-index: 2;\n            max-width: 720px;\n            width: 100%;\n        }\n        .hero-eyebrow {\n            font-size: 12px;\n            font-weight: 500;\n            letter-spacing: 0.2em;\n            text-transform: uppercase;\n            color: var(--c-accent);\n            margin: 0 0 28px 0;\n            opacity: 0;\n            animation: heroFadeUp 0.8s cubic-bezier(0.32,0.72,0,1) 0.3s forwards;\n        }\n        .hero-title {\n            font-family: \'Noto Serif SC\', serif;\n            font-size: clamp(64px, 12vw, 152px);\n            font-weight: 600;\n            line-height: 0.86;\n            letter-spacing: -0.04em;\n            color: #fff;\n            margin: 0;\n            text-shadow: 0 4px 40px rgba(0,0,0,0.4);\n            opacity: 0;\n            animation: heroFadeUp 0.9s cubic-bezier(0.32,0.72,0,1) 0.5s forwards;\n        }\n        .hero-title span { display: block; }\n        .hero-title .accent {\n            font-weight: 700;\n            color: var(--c-accent);\n            letter-spacing: -0.02em;\n        }\n        .hero-sub {\n            font-size: clamp(15px, 1.5vw, 19px);\n            font-weight: 400;\n            line-height: 1.55;\n            color: rgba(255,255,255,0.82);\n            max-width: 420px;\n            margin: 24px 0 0 0;\n            opacity: 0;\n            animation: heroFadeUp 0.8s cubic-bezier(0.32,0.72,0,1) 0.7s forwards;\n        }\n        .hero-search {\n            margin-top: 36px;\n            opacity: 0;\n            animation: heroFadeUp 0.8s cubic-bezier(0.32,0.72,0,1) 0.9s forwards;\n        }\n        .hero-stat {\n            font-size: 12px;\n            font-weight: 500;\n            letter-spacing: 0.1em;\n            color: rgba(255,255,255,0.6);\n            margin: 24px 0 0 0;\n            opacity: 0;\n            animation: heroFadeUp 0.8s cubic-bezier(0.32,0.72,0,1) 1.1s forwards;\n        }\n        @keyframes heroImgReveal {\n            from { opacity: 0; transform: scale(1.08); }\n            to   { opacity: 1; transform: scale(1); }\n        }\n        @keyframes heroFadeUp {\n            from { opacity: 0; transform: translateY(28px); }\n            to   { opacity: 1; transform: translateY(0); }\n        }\n        @media (prefers-reduced-motion: reduce) {\n            .hero-bg img, .hero-eyebrow, .hero-title, .hero-sub, .hero-search, .hero-stat { \n                animation: none !important; opacity: 1 !important; transform: none !important; \n            }\n        }\n        @media (max-width: 640px) {\n            .hero { padding: 0 20px 64px; }\n            .hero-title { font-size: clamp(52px, 15vw, 88px); }\n        }\n    </style>\n</head>\n'
NAV_BAR = ''
PLAYER = '<div class="glow-effect"></div>\n    </div>\n\n    <script>\n        // 沉浸式导航栏滚动监听\n        const nav = document.getElementById(\'mainNav\');\n        const burger = nav.querySelector(\'.nav-burger\');\n        const drawer = document.getElementById(\'navDrawer\');\n        \n        window.addEventListener(\'scroll\', () => {\n            if (window.scrollY > 100) {\n                nav.classList.add(\'scrolled\');\n            } else {\n                nav.classList.remove(\'scrolled\');\n            }\n        }, { passive: true });\n        \n        // 汉堡菜单切换\n        burger.addEventListener(\'click\', () => {\n            const isOpen = drawer.classList.toggle(\'open\');\n            burger.setAttribute(\'aria-expanded\', isOpen);\n        });\n        \n        // 光效跟随鼠标\n        document.querySelectorAll(\'.glow-card, .glow-hero\').forEach(el => {\n            const glow = el.querySelector(\'.glow-effect\');\n            if (!glow) return;\n            \n            el.addEventListener(\'mousemove\', (e) => {\n                const rect = el.getBoundingClientRect();\n                glow.style.left = (e.clientX - rect.left) + \'px\';\n                glow.style.top = (e.clientY - rect.top) + \'px\';\n            });\n        });\n        \n        // 触摸设备禁用光效\n        if (\'ontouchstart\' in window) {\n            document.querySelectorAll(\'.glow-effect\').forEach(el => {\n                el.style.display = \'none\';\n            });\n        }\n    </script>\n</body>\n</html>\n'
SCRIPT = ''
CLOSING = '\n</body>\n</html>'
